def custom_skewness(x):
    if len(x) < 3:
        return np.nan
    n = len(x)
    mean = np.mean(x)
    std = np.std(x, ddof=1)
    if std == 0:
        return 0
    return (np.sum((x - mean) ** 3) / n) / (std ** 3)

moving_pipe = MovingAggrPipe.from_dataframe(data)
moving_pipe = moving_pipe | moving_aggregate(columns='returns', function=custom_skewness, window=30, output_suffix='_skew')
